#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005
int parent[MAXN], rank[MAXN], teeth[MAXN];
int find(int x) { return parent[x] == x ? x : (parent[x] = find(parent[x])); }
void unionSet(int x, int y) { int rootx = find(x), rooty = find(y); if (rootx != rooty) { if (rank[rootx] > rank[rooty]) { parent[rooty] = rootx; } else if (rank[rootx] < rank[rooty]) { parent[rootx] = rooty; } else { parent[rooty] = rootx; rank[rootx]++; } }}
int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    for (int i = 1; i <= N; i++) {
        scanf("%d", &teeth[i]);
        parent[i] = i;
        rank[i] = 0;
    }
    for (int i = 0; i < M; i++) {
        int type;
        scanf("%d", &type);
        if (type == 1) {
            int X, C;
            scanf("%d %d", &X, &C);
            teeth[X] = C;
        } else if (type == 2) {
            int X, Y;
            scanf("%d %d", &X, &Y);
            unionSet(X, Y);
        } else {
            int X, Y, V;
            scanf("%d %d %d", &X, &Y, &V);
            if (find(X) != find(Y)) {
                printf("0\n");
            } else {
                // calculate rotation speed
                int speed = V;
                int current = X;
                while (current != Y) {
                    // find the next gear in the path
                    for (int j = 1; j <= N; j++) {
                        if (find(j) == find(current) && j != current) {
                            current = j;
                            break;
                        }
                    }
                    // update the rotation speed
                    speed = -speed * teeth[X] / teeth[current];
                    X = current;
                }
                printf("%d/%d\n", speed, 1);
            }
        }
    }
    return 0;
}

